1	/**
2	 * TR-808 Drum Machine panel.
3	 * Pad grid, step sequencer rows per instrument, per-instrument knobs,
4	 * pattern A/B selector, accent row, current step indicator.
5	 */
6	
7	import { tokens } from "@ui/tokens/tokens";
8	import { StepButton } from "@ui/controls/StepButton";
9	import { DrumPad } from "@ui/controls/DrumPad";
10	import { DRUM_INSTRUMENTS, PARAM_RANGES } from "@audio/drum-machine/drum-types";
11	import type {
12	  DrumInstrumentId,
13	  DrumInstrumentParams,
14	  DrumPattern,
15	} from "@audio/drum-machine/drum-types";
16	
17	type DrumMachinePanelProps = {
18	  pattern: DrumPattern;
19	  currentStep: number;
20	  activePatternName: string;
21	  onToggleStep: (instrumentId: DrumInstrumentId, stepIndex: number) => void;
22	  onSetAccent: (stepIndex: number, accent: boolean) => void;
23	  onTriggerPad: (instrumentId: DrumInstrumentId) => void;
24	  onParamChange: (
25	    instrumentId: DrumInstrumentId,
26	    key: keyof DrumInstrumentParams,
27	    value: number,
28	  ) => void;
29	  onSwitchPattern: (name: string) => void;
30	  onClearPattern: () => void;
31	  params: Record<DrumInstrumentId, DrumInstrumentParams>;
32	};
33	
34	const BORDER = String(tokens.border.width) + "px solid " + tokens.color.gray700;
35	
36	const labelStyle: React.CSSProperties = {
37	  fontFamily: tokens.font.mono,
38	  fontSize: tokens.text.xs,
39	  color: tokens.color.gray300,
40	  textTransform: "uppercase",
41	  letterSpacing: "0.1em",
42	  width: 64,
43	  textAlign: "right",
44	  flexShrink: 0,
45	};
46	
47	function ParamKnob({
48	  label,
49	  value,
50	  min,
51	  max,
52	  step,
53	  onChange,
54	}: {
55	  label: string;
56	  value: number;
57	  min: number;
58	  max: number;
59	  step: number;
60	  onChange: (v: number) => void;
61	}): React.JSX.Element {
62	  return (
63	    <div
64	      style={{
65	        display: "flex",
66	        flexDirection: "column",
67	        alignItems: "center",
68	        gap: 1,
69	      }}
70	    >
71	      <span
72	        style={{
73	          fontFamily: tokens.font.mono,
74	          fontSize: tokens.text.xs - 1,
75	          color: tokens.color.gray300,
76	        }}
77	      >
78	        {label}
79	      </span>
80	      <input
81	        type="range"
82	        min={min}
83	        max={max}
84	        step={step}
85	        value={value}
86	        onChange={(e) => {
87	          onChange(Number(e.target.value));
88	        }}
89	        style={{ width: 48, accentColor: tokens.color.amber }}
90	        aria-label={label}
91	      />
92	    </div>
93	  );
94	}
95	
96	function InstrumentRow({
97	  instrumentId,
98	  instrumentLabel,
99	  steps,
100	  currentStep,
101	  params,
102	  onToggle,
103	  onTriggerPad,
104	  onParamChange,
105	}: {
106	  instrumentId: DrumInstrumentId;
107	  instrumentLabel: string;
108	  steps: DrumPattern["steps"];
109	  currentStep: number;
110	  params: DrumInstrumentParams;
111	  onToggle: (step: number) => void;
112	  onTriggerPad: () => void;
113	  onParamChange: (key: keyof DrumInstrumentParams, value: number) => void;
114	}): React.JSX.Element {
115	  return (
116	    <div
117	      data-testid={`instrument-row-${instrumentId}`}
118	      style={{ display: "flex", alignItems: "center", gap: tokens.space[2] }}
119	    >
120	      <DrumPad label={instrumentLabel} onTrigger={onTriggerPad} size={32} />
121	      <span style={labelStyle}>{instrumentId.toUpperCase()}</span>
122	      <div style={{ display: "flex", gap: 2 }}>
123	        {steps.map((step, i) => (
124	          <StepButton
125	            key={i}
126	            active={step.triggers[instrumentId]}
127	            current={i === currentStep}
128	            onToggle={() => {
129	              onToggle(i);
130	            }}
131	            index={i}
132	          />
133	        ))}
134	      </div>
135	      <div
136	        style={{
137	          display: "flex",
138	          gap: tokens.space[1],
139	          marginLeft: tokens.space[2],
140	        }}
141	      >
142	        <ParamKnob
143	          label="Tone"
144	          value={params.tone}
145	          min={PARAM_RANGES.tone.min}
146	          max={PARAM_RANGES.tone.max}
147	          step={100}
148	          onChange={(v) => {
149	            onParamChange("tone", v);
150	          }}
151	        />
152	        <ParamKnob
153	          label="Decay"
154	          value={params.decay}
155	          min={PARAM_RANGES.decay.min}
156	          max={PARAM_RANGES.decay.max}
157	          step={0.01}
158	          onChange={(v) => {
159	            onParamChange("decay", v);
160	          }}
161	        />
162	        <ParamKnob
163	          label="Tune"
164	          value={params.tune}
165	          min={PARAM_RANGES.tune.min}
166	          max={PARAM_RANGES.tune.max}
167	          step={0.01}
168	          onChange={(v) => {
169	            onParamChange("tune", v);
170	          }}
171	        />
172	        <ParamKnob
173	          label="Vol"
174	          value={params.volume}
175	          min={PARAM_RANGES.volume.min}
176	          max={PARAM_RANGES.volume.max}
177	          step={0.01}
178	          onChange={(v) => {
179	            onParamChange("volume", v);
180	          }}
181	        />
182	      </div>
183	    </div>
184	  );
185	}
186	
187	function AccentRow({
188	  steps,
189	  currentStep,
190	  onSetAccent,
191	}: {
192	  steps: DrumPattern["steps"];
193	  currentStep: number;
194	  onSetAccent: (stepIndex: number, accent: boolean) => void;
195	}): React.JSX.Element {
196	  return (
197	    <div
198	      data-testid="accent-row"
199	      style={{ display: "flex", alignItems: "center", gap: tokens.space[2] }}
200	    >
201	      <div style={{ width: 32 }} />
202	      <span style={labelStyle}>ACC</span>
203	      <div style={{ display: "flex", gap: 2 }}>
204	        {steps.map((step, i) => (
205	          <button
206	            key={i}
207	            type="button"
208	            aria-label={`Accent ${String(i + 1)}`}
209	            aria-pressed={step.accent}
210	            onClick={() => {
211	              onSetAccent(i, !step.accent);
212	            }}
213	            style={{
214	              display: "inline-flex",
215	              alignItems: "center",
216	              justifyContent: "center",
217	              width: 24,
218	              height: 12,
219	              padding: 0,
220	              border: BORDER,
221	              borderRadius: 0,
222	              background: step.accent
223	                ? tokens.color.pink
224	                : tokens.color.gray900,
225	              cursor: "pointer",
226	              borderColor: i === currentStep ? tokens.color.white : undefined,
227	            }}
228	          />
229	        ))}
230	      </div>
231	    </div>
232	  );
233	}
234	
235	export function DrumMachinePanel({
236	  pattern,
237	  currentStep,
238	  activePatternName,
239	  onToggleStep,
240	  onSetAccent,
241	  onTriggerPad,
242	  onParamChange,
243	  onSwitchPattern,
244	  onClearPattern,
245	  params,
246	}: DrumMachinePanelProps): React.JSX.Element {
247	  return (
248	    <div
249	      data-testid="drum-machine-panel"
250	      style={{
251	        display: "flex",
252	        flexDirection: "column",
253	        gap: tokens.space[1],
254	        padding: tokens.space[2],
255	        backgroundColor: tokens.color.gray900,
256	        fontFamily: tokens.font.mono,
257	        fontSize: tokens.text.sm,
258	        color: tokens.color.gray100,
259	        overflow: "auto",
260	      }}
261	    >
262	      {/* Header: title + pattern buttons */}
263	      <div
264	        style={{
265	          display: "flex",
266	          alignItems: "center",
267	          gap: tokens.space[2],
268	          borderBottom: BORDER,
269	          paddingBottom: tokens.space[1],
270	        }}
271	      >
272	        <span
273	          style={{
274	            fontFamily: tokens.font.mono,
275	            fontSize: tokens.text.lg,
276	            color: tokens.color.amber,
277	            fontWeight: 700,
278	          }}
279	        >
280	          TR-808
281	        </span>
282	        <button
283	          type="button"
284	          aria-label="Pattern A"
285	          onClick={() => {
286	            onSwitchPattern("A");
287	          }}
288	          style={{
289	            fontFamily: tokens.font.mono,
290	            fontSize: tokens.text.xs,
291	            padding: "2px 8px",
292	            border: BORDER,
293	            background:
294	              activePatternName === "A"
295	                ? tokens.color.amber
296	                : tokens.color.gray900,
297	            color:
298	              activePatternName === "A"
299	                ? tokens.color.black
300	                : tokens.color.gray300,
301	            cursor: "pointer",
302	          }}
303	        >
304	          A
305	        </button>
306	        <button
307	          type="button"
308	          aria-label="Pattern B"
309	          onClick={() => {
310	            onSwitchPattern("B");
311	          }}
312	          style={{
313	            fontFamily: tokens.font.mono,
314	            fontSize: tokens.text.xs,
315	            padding: "2px 8px",
316	            border: BORDER,
317	            background:
318	              activePatternName === "B"
319	                ? tokens.color.amber
320	                : tokens.color.gray900,
321	            color:
322	              activePatternName === "B"
323	                ? tokens.color.black
324	                : tokens.color.gray300,
325	            cursor: "pointer",
326	          }}
327	        >
328	          B
329	        </button>
330	        <button
331	          type="button"
332	          aria-label="Clear"
333	          onClick={onClearPattern}
334	          style={{
335	            fontFamily: tokens.font.mono,
336	            fontSize: tokens.text.xs,
337	            padding: "2px 8px",
338	            border: BORDER,
339	            background: tokens.color.gray900,
340	            color: tokens.color.red,
341	            cursor: "pointer",
342	          }}
343	        >
344	          CLR
345	        </button>
346	      </div>
347	
348	      {/* Accent row */}
349	      <AccentRow
350	        steps={pattern.steps}
351	        currentStep={currentStep}
352	        onSetAccent={onSetAccent}
353	      />
354	
355	      {/* Instrument rows */}
356	      {DRUM_INSTRUMENTS.map((inst) => (
357	        <InstrumentRow
358	          key={inst.id}
359	          instrumentId={inst.id}
360	          instrumentLabel={inst.label}
361	          steps={pattern.steps}
362	          currentStep={currentStep}
363	          params={params[inst.id]}
364	          onToggle={(step) => {
365	            onToggleStep(inst.id, step);
366	          }}
367	          onTriggerPad={() => {
368	            onTriggerPad(inst.id);
369	          }}
370	          onParamChange={(key, value) => {
371	            onParamChange(inst.id, key, value);
372	          }}
373	        />
374	      ))}
375	    </div>
376	  );
377	}
