66	            background: "transparent",
67	            color: "var(--color-red, #f44)",
68	            cursor: "pointer",
69	            fontSize: "0.875rem",
70	          }}
71	        >
72	          Reload
73	        </button>
74	      </div>
75	    );
76	  }
77	}
