1	/**
2	 * Synth editor panel: oscillator type selectors, filter cutoff/resonance knobs,
3	 * ADSR sliders, LFO rate/depth knobs.
4	 * Neo-brutalist styling consistent with the design system.
5	 */
6	
7	import { useCallback } from "react";
8	import { tokens } from "@ui/tokens/tokens";
9	import { useSynthStore } from "@state/synth";
10	import { VirtualKeyboard } from "./VirtualKeyboard";
11	import { ModulationMatrix } from "./ModulationMatrix";
12	import type { SynthParameterMap } from "@audio/synth/synth-types";
13	import {
14	  WAVEFORM_TYPES,
15	  FILTER_TYPES,
16	  LFO_SHAPES,
17	} from "@audio/synth/synth-types";
18	
19	type SynthEditorProps = {
20	  trackId: string;
21	  onNoteOn?: (note: number, velocity: number) => void;
22	  onNoteOff?: (note: number) => void;
23	};
24	
25	// ─── Shared Styles ───
26	
27	const BORDER = String(tokens.border.width) + "px solid " + tokens.color.gray700;
28	
29	const sectionStyle: React.CSSProperties = {
30	  border: BORDER,
31	  padding: tokens.space[2],
32	  display: "flex",
33	  flexDirection: "column",
34	  gap: tokens.space[1],
35	};
36	
37	const labelStyle: React.CSSProperties = {
38	  fontFamily: tokens.font.mono,
39	  fontSize: tokens.text.xs,
40	  color: tokens.color.gray300,
41	  textTransform: "uppercase",
42	  letterSpacing: "0.1em",
43	};
44	
45	const controlRowStyle: React.CSSProperties = {
46	  display: "flex",
47	  gap: tokens.space[2],
48	  alignItems: "center",
49	};
50	
51	// ─── Reusable Controls ───
52	
53	function Knob({
54	  label,
55	  value,
56	  min,
57	  max,
58	  step,
59	  unit,
60	  onChange,
61	}: {
62	  label: string;
63	  value: number;
64	  min: number;
65	  max: number;
66	  step: number;
67	  unit?: string;
68	  onChange: (v: number) => void;
69	}): React.JSX.Element {
70	  return (
71	    <div
72	      style={{
73	        display: "flex",
74	        flexDirection: "column",
75	        alignItems: "center",
76	        gap: 2,
77	      }}
78	    >
79	      <span style={labelStyle}>{label}</span>
80	      <input
81	        type="range"
82	        min={min}
83	        max={max}
84	        step={step}
85	        value={value}
86	        onChange={(e) => {
87	          onChange(Number(e.target.value));
88	        }}
89	        style={{ width: 60, accentColor: tokens.color.blue }}
90	        data-testid={"knob-" + label.toLowerCase().replace(/\s/g, "-")}
91	      />
92	      <span style={{ ...labelStyle, fontSize: tokens.text.xs - 1 }}>
93	        {value.toFixed(step < 1 ? 2 : 0)}
94	        {unit ?? ""}
95	      </span>
96	    </div>
97	  );
98	}
99	
100	function TypeSelector<T extends string>({
101	  label,
102	  value,
103	  options,
104	  onChange,
105	}: {
106	  label: string;
107	  value: T;
108	  options: readonly T[];
109	  onChange: (v: T) => void;
110	}): React.JSX.Element {
111	  return (
112	    <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
113	      <span style={labelStyle}>{label}</span>
114	      <select
115	        value={value}
116	        onChange={(e) => {
117	          onChange(e.target.value as T);
118	        }}
119	        data-testid={"select-" + label.toLowerCase().replace(/\s/g, "-")}
120	        style={{
121	          backgroundColor: tokens.color.gray900,
122	          color: tokens.color.gray100,
123	          border: BORDER,
124	          fontFamily: tokens.font.mono,
125	          fontSize: tokens.text.xs,
126	          padding: "2px 4px",
127	        }}
128	      >
129	        {options.map((opt) => (
130	          <option key={opt} value={opt}>
131	            {opt}
132	          </option>
133	        ))}
134	      </select>
135	    </div>
136	  );
137	}
138	
139	// ─── Main Editor ───
140	
141	export function SynthEditor({
142	  trackId,
143	  onNoteOn,
144	  onNoteOff,
145	}: SynthEditorProps): React.JSX.Element {
146	  const params = useSynthStore((s) => s.synths[trackId]?.params);
147	  const legato = useSynthStore((s) => s.synths[trackId]?.legato ?? false);
148	  const setParam = useSynthStore((s) => s.setParam);
149	  const setLegato = useSynthStore((s) => s.setLegato);
150	
151	  const p = params ?? useSynthStore.getState().getParams(trackId);
152	
153	  const set = useCallback(
154	    <K extends keyof SynthParameterMap>(
155	      key: K,
156	      value: SynthParameterMap[K],
157	    ) => {
158	      setParam(trackId, key, value);
159	    },
160	    [trackId, setParam],
161	  );
162	
163	  const handleNoteOn = useCallback(
164	    (note: number, velocity: number) => {
165	      onNoteOn?.(note, velocity);
166	    },
167	    [onNoteOn],
168	  );
169	
170	  const handleNoteOff = useCallback(
171	    (note: number) => {
172	      onNoteOff?.(note);
173	    },
174	    [onNoteOff],
175	  );
176	
177	  return (
178	    <div
179	      data-testid="synth-editor"
180	      style={{
181	        display: "flex",
182	        flexDirection: "column",
183	        gap: tokens.space[2],
184	        padding: tokens.space[2],
185	        backgroundColor: tokens.color.gray900,
186	        fontFamily: tokens.font.mono,
187	        fontSize: tokens.text.sm,
188	        color: tokens.color.gray100,
189	        overflow: "auto",
190	      }}
191	    >
192	      {/* Oscillators Row */}
193	      <div style={{ display: "flex", gap: tokens.space[2] }}>
194	        {/* OSC 1 */}
195	        <section style={sectionStyle} data-testid="osc1-section">
196	          <span style={{ ...labelStyle, color: tokens.color.blue }}>OSC 1</span>
197	          <div style={controlRowStyle}>
198	            <TypeSelector
199	              label="Type"
200	              value={p.osc1Type}
201	              options={WAVEFORM_TYPES}
202	              onChange={(v) => {
203	                set("osc1Type", v);
204	              }}
205	            />
206	            <Knob
207	              label="Oct"
208	              value={p.osc1Octave}
209	              min={-2}
210	              max={2}
211	              step={1}
212	              onChange={(v) => {
213	                set("osc1Octave", v);
214	              }}
215	            />
216	            <Knob
217	              label="Detune"
218	              value={p.osc1Detune}
219	              min={-100}
220	              max={100}
221	              step={1}
222	              unit="c"
223	              onChange={(v) => {
224	                set("osc1Detune", v);
225	              }}
226	            />
227	            <Knob
228	              label="Level"
229	              value={p.osc1Level}
230	              min={0}
231	              max={1}
232	              step={0.01}
233	              onChange={(v) => {
234	                set("osc1Level", v);
235	              }}
236	            />
237	          </div>
