              pointerEvents: "none",
            }}
          >
            {routes.map((route) => {
              const srcIdx = MOD_SOURCES.indexOf(route.source);
              const destIdx = MOD_DESTINATIONS.indexOf(route.destination);
              const srcY = 20 + srcIdx * 22;
              const destY = 20 + destIdx * 22;
              return (
                <line
                  key={route.id}
